{"code": "import json
import re

# Access the stored variable directly
brca_patients = var_functions.query_db:28
print('Total BRCA female patients: ' + str(len(brca_patients)))

# Extract patient barcodes and histological types
patients = []
for record in brca_patients:
    desc = record['Patient_description']
    hist_type = record['histological_type']

    # Extract barcode using regex
    match = re.search('TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}', desc)
    if match:
        patients.append({
            'barcode': match.group(0),
            'hist_type': hist_type
        })

print('Extracted ' + str(len(patients)) + ' patient barcodes')

# Count histological types
hist_counts = {}
for p in patients:
    h = p['hist_type']
    hist_counts[h] = hist_counts.get(h, 0) + 1

print('Histological types:')
for h, c in hist_counts.items():
    print('  ' + h + ': ' + str(c))

# Prepare output
output = {
    'patients': patients,
    'hist_counts': hist_counts
}
print('__RESULT__:')
print(json.dumps(output))"}
